export function InputField({text, placeholder, className, isTextarea = false, value, onChange}) {
    return (
        <div className='flex flex-col gap-2'>
            <div className='flex gap-1'>
                <label>
                    <p className='text-white text-[12px] opacity-80 font-light'>{text}</p>
                </label>
                <div className='text-red-500 text-[12px]'>
                    <p>*</p>
                </div>
            </div>
            {/* <input type='text' placeholder={placeholder} className={`border border-[#303030] !text-white text-sm rounded-[4px] h-[48px] pr-4 pl-4 w-[311px] ${className}`}/> */}

            {isTextarea ? (
                <textarea
                    placeholder={placeholder}
                    className={`border w-full border-[#303030] text-white text-sm rounded-[4px] p-4 w-[300px] resize-none ${className}`}
                />
            ) : (
                <input
                    type="text"
                    placeholder={placeholder}
                    value={value}
                    onChange={onChange}
                    className={`focus:blur-10 focus:shadow-[0_0_2px_#1B1EFF] focus:shadow-[#1B1EFF] focus:ring-2
                        focus:ring-[#3B3C9A]/30 outline-none border focus:border-[#3B3C9A] transition border-[#303030] w-full text-white text-sm rounded-[4px] h-[48px] px-4 w-[300px] lg:max-w-full ${className}`}
                />
            )}
        </div>
    );
}

